mapper.select:
SELECT t.*, ua.role FROM teacher t LEFT JOIN user_account ua ON t.teacher_id = ua.related_id AND (ua.role='TEACHER' OR ua.role='ADMIN') WHERE 1=1
AND (t.teacher_no LIKE CONCAT('%',#{keyword},'%') OR t.teacher_name LIKE CONCAT('%',#{keyword},'%') OR t.office LIKE CONCAT('%',#{keyword},'%') OR t.title LIKE CONCAT('%',#{keyword},'%'))
ORDER BY t.create_time DESC LIMIT #{offset},#{size}
